export type Json =
  | string
  | number
  | boolean
  | null
  | { [key: string]: Json | undefined }
  | Json[];

// ============================================================================
// ENUM TYPES
// ============================================================================

export type GameStatus = 'waiting' | 'countdown' | 'playing' | 'intermission' | 'finished' | 'cancelled';
export type GameType = 'casual' | 'ranked' | 'custom' | 'tournament' | 'private';
export type RankTier = 'bronze' | 'silver' | 'gold' | 'platinum' | 'diamond' | 'master' | 'grandmaster';
export type AchievementRarity = 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
export type AchievementCategory = 'combat' | 'survival' | 'social' | 'progression' | 'special' | 'seasonal' | 'secret';
export type TournamentStatus = 'draft' | 'registration' | 'check_in' | 'active' | 'finished' | 'cancelled';
export type TournamentFormat = 'single_elimination' | 'double_elimination' | 'round_robin' | 'swiss';
export type TournamentParticipantStatus = 'registered' | 'checked_in' | 'active' | 'eliminated' | 'winner' | 'disqualified' | 'no_show';
export type FriendshipStatus = 'pending' | 'accepted' | 'blocked' | 'declined';
export type ChatMessageType = 'text' | 'emoji' | 'system' | 'quick_chat';
export type ConnectionStatus = 'connected' | 'disconnected' | 'reconnecting';
export type NotificationType =
  | 'friend_request'
  | 'friend_accepted'
  | 'game_invite'
  | 'tournament_invite'
  | 'tournament_starting'
  | 'tournament_match_ready'
  | 'achievement_unlocked'
  | 'rank_changed'
  | 'system_message';
export type ReportReason = 'cheating' | 'harassment' | 'inappropriate_name' | 'griefing' | 'other';
export type ReportStatus = 'pending' | 'reviewed' | 'action_taken' | 'dismissed';
export type MatchmakingStatus = 'searching' | 'matching' | 'found' | 'cancelled';

