export interface GameSettings {
  maxPlayers: number;
  roundTime: number;
  roundsToWin: number;
  suddenDeathTime: number;
  powerupSpawnRate: number;
  allowSpectators: boolean;
  isPrivate?: boolean;
  startingBombs?: number;
  startingRadius?: number;
  startingSpeed?: number;
}

export interface MapTileData {
  tiles: number[][];
  version?: number;
}

export interface SpawnPoint {
  x: number;
  y: number;
}

export interface PowerupDistribution {
  bomb?: number;
  fire?: number;
  speed?: number;
  kick?: number;
  punch?: number;
  skull?: number;
}

export interface AchievementCriteria {
  type: 'kills' | 'wins' | 'games' | 'win_streak' | 'elo' | 'rank' | 'custom';
  target: number | string;
  conditions?: Record<string, unknown>;
}

export interface TournamentPrizePool {
  '1st'?: string;
  '2nd'?: string;
  '3rd'?: string;
  [key: string]: string | undefined;
}

export interface TournamentBracket {
  rounds: TournamentMatch[][];
}

export interface TournamentMatch {
  id: number;
  round: number;
  player1_id?: string;
  player2_id?: string;
  winner_id?: string;
  status: 'pending' | 'ready' | 'in_progress' | 'completed' | 'bye';
  game_id?: string;
  score?: { player1: number; player2: number };
}

export interface ReplayHighlight {
  tick: number;
  type: 'kill' | 'multikill' | 'clutch' | 'close_call';
  description: string;
}

export interface PlayerSettings {
  sfxVolume?: number;
  musicVolume?: number;
  showPlayerNames?: boolean;
  showPing?: boolean;
  colorblindMode?: boolean;
}

